(window.webpackJsonp=window.webpackJsonp||[]).push([[101],{457:function(t,e,s){"use strict";s.r(e);var v=s(42),_=Object(v.a)({},(function(){var t=this,e=t.$createElement,s=t._self._c||e;return s("ContentSlotsDistributor",{attrs:{"slot-key":t.$parent.slotKey}},[s("h1",{attrs:{id:"不去会死！"}},[s("a",{staticClass:"header-anchor",attrs:{href:"#不去会死！"}},[t._v("#")]),t._v(" 不去会死！")]),t._v(" "),s("p",[t._v("到不了的都叫远方。")]),t._v(" "),s("Picture",{staticStyle:{width:"300px"},attrs:{name:"https://img3.doubanio.com/view/subject/l/public/s4232721.jpg",outside:""}}),t._v(" "),s("p",[t._v("大概是看的书比较少（当然这里不包括课本），我能清楚地记得每本书是在什么时候看的。这本书是在前年（15年）的这个时候看的。那会儿刚换新工作不久，为了不在路上浪费太多时间我搬到了公司附近。现在想来那时确实太冒险，试用期都还没过呢。我现在不太记得试用期是几个月了，就当是三个月吧，这样想心里会好受点。")]),t._v(" "),s("p",[t._v("我不知道出于什么原因，公司一直没给我转正，期间我也口头上询问过。开始还有几分期待，后来就产生了非走不可的念头了。可笑的是当我要离职时才想到要给我转正，或许这不过是他们的客套话而已，让他们自己良心好受一点，等项目差不多时就把我炒掉，反正没转正又不用赔偿。")]),t._v(" "),s("p",[t._v("虽说我心里各种不爽，但我还是本着我的职业道德在项目完成差不多时才提出离职的。自己先走总比别人让你走要来得体面，大多数老板是不会讲情义的，他们尬尴也是尴尬那一会，当你从会议室出来拿东西走人后他们的心情会是无比舒畅。或许是我主动走人让他们避免了那一会尴尬，所以工资是当天就给我结清了没有等到下个月。")]),t._v(" "),s("p",[t._v("这四个月是痛苦的，住的是一间本来就不大的房分隔成的小隔间，所谓的公共空间不过就是过道上的厨房和还算标准的阳台。隔间里不开空调总有股说不出的怪味道，感觉都要呼吸不过来，一开窗户外面嘈杂的空调声更是要抓狂，关键是房租还占了工资的四分之一，看来想步行上班的代价还是蛮大的。我是有幽闭恐惧症的，狭小的空间让我感觉到无比压抑。当一个人躯体不自由时，精神上一定要有信念，否则容易得忧郁症，而我买的这本书则让我还不至于放弃对生活的希望。")]),t._v(" "),s("p",[t._v("书是一个人日本小伙写的，作者从小就想‘环游世界’，该书记录了作者从北美洲开始顺时针骑车环绕世界寻找自己心中的‘世界第一’的旅程，旅程预期三年半实际七年半，文字朴实，书中偶有作者旅行中的照片与素描。作者从小的梦想就是环游世界，在不大的时候就已经有‘环游和歌山县一周’、‘近一周’、‘环游日本一周’的经历，他的的经历让我产生了共鸣，这当然不是因为我在高中时期也有四次稍微远一点的骑行经历，而是他追寻的恰巧是我在意的。")]),t._v(" "),s("p",[t._v("不知道从什么时候开始，在我心里就有了两个非去不可的地方，一个是海边，另一个是西藏。高中毕业的那个暑假是我第一次看海，那会那里的名字还不叫“西湾公园”。第一次看海的体验不是很好，海边是各种生活垃圾，海水不是想象的蔚蓝色，空气中带有一股咸臭味，但还是被那种广袤无际所震撼。工作后徒步过几次，最喜欢的还是有海的路线，世上我唯一看不厌的或许就是海了吧，这也是我喜欢深圳的其中一个原因，有海可看。")]),t._v(" "),s("p",[t._v("至于西藏，它仍待我去涉足。14 年的时候，曾信誓旦旦说后年（16年）要从深圳开始骑去西藏，甚至还去搜了搜什么时候去比较合适，奈何生活变数太多没能去成。到达远方的方式很多，但不是每个人都有说走就走的勇气和资本。我不所认为“风景什么时候去看都一样”，相反在不同时间风景和人都可能不一样，风景有可能不在了，人或许心境变了。")]),t._v(" "),s("p",[t._v("远方不远，争取早点到达吧。")])],1)}),[],!1,null,null,null);e.default=_.exports}}]);